import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintReturnsCSVPrinter() throws IOException {
        Appendable appendable = new StringBuilder();
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }

    @Test
    void testPrintWithMockAppendable() throws IOException {
        Appendable appendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }

    @Test
    void testPrintThrowsIOException() {
        Appendable appendable = mock(Appendable.class);
        try {
            doThrow(new IOException("test exception")).when(appendable).append(any(CharSequence.class));
        } catch (IOException e) {
            // This won't happen here, just to satisfy compiler
        }
        // The CSVFormat.print method itself does not write on appendable, so IOException is unlikely here.
        // But we can test that print returns CSVPrinter even if appendable throws on append.
        assertDoesNotThrow(() -> {
            CSVPrinter printer = csvFormat.print(appendable);
            assertNotNull(printer);
        });
    }
}
